package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.joinengine;

/**
 * Mutable planner reward aggregates for bandit policies.
 */
public final class PlannerBanditStats {

	private long pulls;
	private double rewardSum;
	private double rewardSquaredSum;

	public PlannerBanditStats() {
	}

	public PlannerBanditStats(long pulls, double rewardSum, double rewardSquaredSum) {
		this.pulls = Math.max(0L, pulls);
		this.rewardSum = Double.isFinite(rewardSum) ? rewardSum : 0.0d;
		this.rewardSquaredSum = Double.isFinite(rewardSquaredSum) ? rewardSquaredSum : 0.0d;
	}

	public void add(double reward) {
		if (!Double.isFinite(reward)) {
			return;
		}
		pulls++;
		rewardSum += reward;
		rewardSquaredSum += reward * reward;
	}

	public long getPulls() {
		return pulls;
	}

	public double getRewardSum() {
		return rewardSum;
	}

	public double getRewardSquaredSum() {
		return rewardSquaredSum;
	}

	public double meanReward() {
		if (pulls <= 0) {
			return 0.0d;
		}
		return rewardSum / pulls;
	}

	public double sampleVariance() {
		if (pulls <= 1) {
			return 1.0d;
		}
		double mean = meanReward();
		double centered = (rewardSquaredSum / pulls) - (mean * mean);
		if (!Double.isFinite(centered) || centered <= 0.0d) {
			return 1.0d;
		}
		return centered;
	}

	public PlannerBanditStats copy() {
		return new PlannerBanditStats(pulls, rewardSum, rewardSquaredSum);
	}
}
